# Verify no duplicates
new_slugs = [p["slug"] for p in new_products]
dup_new = [s for s in new_slugs if new_slugs.count(s) > 1]
dup_existing = [s for s in new_slugs if s in existing_slugs]

print(f"New products: {len(new_products)}")
print(f"Duplicates within new batch: {set(dup_new)}")
print(f"Conflicts with existing: {dup_existing}")

if not dup_new and not dup_existing:
    combined = products + new_products
    with open("src/data/products.json", "w", encoding="utf-8") as f:
        json.dump(combined, f, indent=2, ensure_ascii=False)
    print(f"SUCCESS: Wrote {len(combined)} total products to products.json")
else:
    print("ABORTED: Duplicate slugs found. Fix before writing.")
    sys.exit(1)
